53	export class GradingService<
54	  A extends { id: string; maxScore: number; dueDate?: Date; rubric: RubricCriterion[] },
55	  S extends { id: string; assignmentId: string; studentId: string; submittedAt: Date },
56	  C extends { id: string; instructorIds: string[] },
57	> {
58	  constructor(private deps: GradingServiceDeps<A, S, C>) {}
59	
60	  /**
61	   * Check whether a grader may grade a given submission.
62	   * Admins can grade any submission. Instructors may only grade submissions
63	   * belonging to a course they are assigned to.
64	   */
65	  async canGrade(grader: Grader, submissionId: string): Promise<boolean> {
66	    if (grader.role === 'admin') return true
67	    if (grader.role !== 'instructor') return false
68	
69	    const submission = await this.deps.getSubmission(submissionId)
70	    if (!submission) return false
71	
72	    const course = await this.deps.getCourseForAssignment(submission.assignmentId)
73	    if (!course) return false
74	
75	    return course.instructorIds.includes(grader.id)
76	  }
77	
78	  /**
79	   * Grade a submission against the assignment rubric.
80	   *
81	   * Validates:
82	   * - Grader has permission (instructor or admin)
83	   * - Submission exists and belongs to the assignment
84	   * - Assignment exists
85	   * - Course exists and grader is authorized for it
86	   * - Submission has not already been graded
87	   * - All scores are within [0, criterion.maxPoints]
88	   * - Total does not exceed assignment.maxScore
89	   * - No duplicate criterion names
90	   * - All rubric criteria are scored
91	   */
92	  async gradeSubmission(options: GradeSubmissionOptions): Promise<GradingResult<S>> {
93	    const { submissionId, rubricScores, grader, feedback } = options
94	
95	    // Permission check
96	    const submission = await this.deps.getSubmission(submissionId)
97	    if (!submission) {
98	      return { success: false, error: `Submission "${submissionId}" not found.` }
99	    }
100	
101	    if (grader.role === 'student') {
102	      return { success: false, error: 'Students are not authorized to grade submissions.' }
103	    }
104	
105	    const assignment = await this.deps.getAssignment(submission.assignmentId)
106	    if (!assignment) {
107	      return { success: false, error: `Assignment for submission "${submissionId}" not found.` }
108	    }
109	
110	    const course = await this.deps.getCourseForAssignment(submission.assignmentId)
111	    if (!course) {
112	      return { success: false, error: 'Course not found — not authorized to grade this submission.' }
113	    }
114	
115	    const isInstructor = grader.role === 'instructor'
116	    if (isInstructor && !course.instructorIds.includes(grader.id)) {
117	      return { success: false, error: 'You are not authorized to grade submissions for this course.' }
118	    }
119	
120	    // Prevent re-grading
121	    const current = await this.deps.getSubmission(submissionId)
122	    if (current && (current as unknown as { status?: string }).status === 'graded') {
123	      return { success: false, error: 'This submission has already been graded.' }
124	    }
125	
126	    // Build rubric lookup
127	    const rubricMap = new Map<string, RubricCriterion>()
128	    for (const item of assignment.rubric) {
129	      rubricMap.set(item.criterion, item)
130	    }
131	
132	    // Validate: all criteria scored
133	    const scoredCriteria = new Set<string>()
134	    for (const rs of rubricScores) {
135	      if (scoredCriteria.has(rs.criterion)) {
136	        return {
137	          success: false,
138	          error: `Duplicate criterion "${rs.criterion}" in rubricScores. Each criterion may appear only once.`,
139	        }
140	      }
141	      scoredCriteria.add(rs.criterion)
142	    }
143	
144	    // Validate unknown criterion names before checking for missing criteria
145	    for (const rs of rubricScores) {
146	      if (!rubricMap.has(rs.criterion)) {
147	        return {
148	          success: false,
149	          error: `Criterion "${rs.criterion}" not found in assignment rubric.`,
150	        }
151	      }
152	    }
153	
154	    const missingCriteria = [...rubricMap.keys()].filter((c) => !scoredCriteria.has(c))
155	    if (missingCriteria.length > 0) {
156	      return {
157	        success: false,
158	        error: `Missing scores for rubric criteria: ${missingCriteria.join(', ')}.`,
159	      }
160	    }
161	
162	    // Validate: scores within bounds and total within maxScore
163	    let totalScore = 0
164	    for (const rs of rubricScores) {
165	      if (rs.score < 0) {
166	        return {
167	          success: false,
168	          error: `Score for "${rs.criterion}" cannot be negative (got ${rs.score}).`,
169	        }
170	      }
171	
172	      const criterion = rubricMap.get(rs.criterion)!
173	      if (rs.score > criterion.maxPoints) {
174	        return {
175	          success: false,
176	          error: `Score for "${rs.criterion}" (${rs.score}) exceeds maxPoints (${criterion.maxPoints}).`,
177	        }
178	      }
179	
180	      totalScore += rs.score
181	    }
182	
183	    if (totalScore > assignment.maxScore) {
184	      return {
185	        success: false,
186	        error: `Total score (${totalScore}) exceeds assignment maxScore (${assignment.maxScore}).`,
187	      }
188	    }
189	
190	    // Determine lateness
191	    const isLate = !!assignment.dueDate && submission.submittedAt > assignment.dueDate
192	
193	    // Persist grade
194	    const updated = await this.deps.updateSubmission(submissionId, {
195	      grade: totalScore,
196	      status: 'graded',
197	      feedback,
198	      rubricScores,
199	    } as Partial<S & { grade: number; status: string; feedback?: string; rubricScores: RubricScore[] }>)
200	
201	    if (!updated) {
202	      return { success: false, error: 'Failed to update submission.' }
203	    }
204	
205	    return {
206	      success: true,
207	      submission: updated as S & { grade: number; status: string; feedback?: string; rubricScores: RubricScore[]; submittedAt: Date; assignmentId: string },
208	      isLate,
209	    }
210	  }
211	}
