14	export function requireRole(...roles: RbacRole[]) {
15	  return function roleGuard(context: RoleContext): RoleError | undefined {
16	    if (!context.user) {
17	      return { error: 'Authentication required', status: 401 }
18	    }
19	
20	    if (!context.user.role) {
21	      return { error: 'User role not configured', status: 401 }
22	    }
23	
24	    const userRoleLevel = ROLE_HIERARCHY[context.user.role as RbacRole]
25	    const hasSufficientRole = roles.some((requiredRole) => userRoleLevel >= ROLE_HIERARCHY[requiredRole])
26	
27	    if (!hasSufficientRole) {
28	      return {
29	        error: `Forbidden: requires role ${roles.join(' or ')}`,
30	        status: 403,
31	      }
32	    }
33	
34	    return undefined
35	  }
36	}
