29	export interface RouteContext {
30	  user?: AuthenticatedUser
31	  error?: string
32	  status?: number
33	}
34	
35	export interface WithAuthOptions {
36	  roles?: RbacRole[]
37	  optional?: boolean // If true, allow unauthenticated requests (but still validate if token present)
38	}
39	
40	/**
41	 * Higher-order function that wraps an API route handler with authentication.
42	 *
43	 * Usage:
44	 * ```
45	 * export const GET = withAuth(async (req, { user }, routeParams) => {
46	 *   // user is guaranteed to be authenticated here
47	 *   const { params } = routeParams
48	 *   return Response.json({ data: user })
49	 * }, { roles: ['admin', 'editor'] })
50	 * ```
51	 *
52	 * Note: The handler receives (req, context, routeParams) where routeParams
53	 * includes Next.js route params like { params }.
54	 */
55	export function withAuth(
56	  // eslint-disable-next-line @typescript-eslint/no-explicit-any
57	  handler: (req: NextRequest, context: RouteContext, routeParams?: any) => Promise<Response>,
58	  options: WithAuthOptions = {}
59	) {
60	  return async (req: NextRequest, routeParams?: unknown): Promise<Response> => {
61	    const authHeader = req.headers.get('authorization')
62	    const token = extractBearerToken(authHeader)
63	
64	    // If optional and no token, proceed without auth
65	    if (options.optional && !token) {
66	      return handler(req, {}, routeParams)
67	    }
68	
69	    // If no token provided and not optional, reject
70	    if (!token) {
71	      return Response.json(
72	        { error: 'Missing or invalid Authorization header' },
73	        { status: 401 }
74	      )
75	    }
76	
77	    let authContext: RouteContext
78	
79	    try {
80	      const authService = getAuthService()
81	      const result = await authService.verifyAccessToken(token)
82	      if (result.user) {
83	        const roleCheck = checkRole(result.user, options.roles)
84	        if (roleCheck.error) {
85	          return Response.json(
86	            { error: roleCheck.error },
87	            { status: roleCheck.status ?? 401 }
88	          )
89	        }
90	        authContext = { user: result.user }
91	      } else {
92	        authContext = { error: 'User not found', status: 404 }
93	      }
94	    } catch (err) {
95	      const message = err instanceof Error ? err.message : 'Invalid token'
96	      return Response.json({ error: message }, { status: 401 })
97	    }
98	
99	    if (authContext.error) {
100	      return Response.json(
101	        { error: authContext.error },
102	        { status: authContext.status ?? 401 }
103	      )
104	    }
105	
106	    return handler(req, authContext as RouteContext, routeParams)
107	  }
108	}
