1	import type { AuthenticatedUser, RbacRole } from './auth-service'
2	
3	export interface AuthContext {
4	  user?: AuthenticatedUser
5	  error?: string
6	  status?: number
7	}
8	
9	export interface AuthOptions {
10	  roles?: RbacRole[]
11	}
12	
13	/**
14	 * Role hierarchy: higher numbers include permissions of lower numbers
15	 * admin (3) > editor (2) > viewer (1)
16	 */
17	export const ROLE_HIERARCHY: Record<RbacRole, number> = {
18	  admin: 3,
19	  editor: 2,
20	  viewer: 1,
21	}
22	
23	/**
24	 * Extract Bearer token from Authorization header
25	 */
26	export function extractBearerToken(authHeader: string | null): string | null {
27	  if (!authHeader || !authHeader.startsWith('Bearer ')) {
28	    return null
29	  }
30	  return authHeader.slice(7)
31	}
32	
33	/**
34	 * Check if user has one of the required roles (with hierarchical inheritance)
35	 * A user with a higher role can access lower-role resources
36	 */
37	export function checkRole(user: AuthenticatedUser | undefined, roles: RbacRole[] | undefined): AuthContext {
38	  if (!user) {
39	    return { error: 'Authentication required', status: 401 }
40	  }
41	
42	  if (!roles || roles.length === 0) {
43	    return { user }
44	  }
45	
46	  if (!user.role) {
47	    return { error: 'User role not configured', status: 401 }
48	  }
49	
50	  const userRoleLevel = ROLE_HIERARCHY[user.role]
51	  const hasSufficientRole = roles.some((requiredRole) => userRoleLevel >= ROLE_HIERARCHY[requiredRole])
52	
53	  if (!hasSufficientRole) {
54	    return {
55	      error: `Forbidden: requires role ${roles.join(' or ')}`,
56	      status: 403,
57	    }
58	  }
59	
60	  return { user }
61	}
