1	import type { Payload } from 'payload'
2	import type { CollectionSlug } from 'payload'
3	import crypto from 'crypto'
4	import { JwtService } from './jwt-service'
5	
6	export type RbacRole = 'admin' | 'editor' | 'viewer'
7	
8	export interface AuthenticatedUser {
9	  id: number | string
10	  email: string
11	  role: RbacRole
12	  firstName?: string
13	  lastName?: string
14	  isActive: boolean
15	}
16	
17	export interface AuthResult {
18	  accessToken: string
19	  refreshToken: string
20	  user: {
21	    id: number | string
22	    email: string
23	    role: RbacRole
24	  }
25	}
