27	export interface TokenFields {
28	  refreshToken: string | null
29	  tokenExpiresAt: Date | null
30	  lastTokenUsedAt: Date | null
31	}
32	
33	const REFRESH_TOKEN_EXPIRY_MS = 7 * 24 * 60 * 60 * 1000 // 7 days
34	
35	function createError(message: string, status: number): Error & { status: number } {
36	  const err = new Error(message) as Error & { status: number }
37	  err.status = status
38	  return err
39	}
