62	export class AuthService {
63	  constructor(
64	    private payload: Payload,
65	    private jwtService: JwtService,
66	  ) {}
67	
68	  async login(
69	    email: string,
70	    password: string,
71	    _ipAddress: string,
72	    _userAgent: string
73	  ): Promise<AuthResult> {
74	    if (!email) {
75	      throw createError('Email is required', 400)
76	    }
77	
78	    if (!password) {
79	      throw createError('Password is required', 400)
80	    }
81	
82	    const users = await this.payload.find({
83	      collection: 'users' as CollectionSlug,
84	      where: { email: { equals: email } },
85	      limit: 1,
86	    })
87	    const user = users.docs[0]
88	
89	    if (!user) {
90	      throw createError('Invalid credentials', 401)
91	    }
92	
93	    const userId = (user as any).id
94	    const role = (user as any).role as RbacRole
95	    const isActive = (user as any).isActive ?? true
96	    const hash = (user as any).hash as string | null | undefined
97	    const salt = (user as any).salt as string | null | undefined
98	
99	    if (!isActive) {
100	      throw createError('Account is inactive', 403)
101	    }
102	
103	    // Verify password against stored hash
104	    if (!hash || !salt) {
105	      throw createError('Invalid credentials', 401)
106	    }
107	
108	    const passwordValid = await verifyPassword(password, hash, salt)
109	    if (!passwordValid) {
110	      throw createError('Invalid credentials', 401)
111	    }
112	
113	    // Generate tokens
114	    const tokenPayload = {
115	      userId: String(userId),
116	      email,
117	      role,
118	      sessionId: `session-${userId}-${Date.now()}`,
119	      generation: 0,
120	    }
121	
122	    const accessToken = await this.jwtService.signAccessToken(tokenPayload)
123	    const refreshToken = await this.jwtService.signRefreshToken(tokenPayload)
124	
125	    // Calculate expiry
126	    const tokenExpiresAt = new Date(Date.now() + REFRESH_TOKEN_EXPIRY_MS)
127	
128	    // Update user with token fields and lastLogin (actual login event)
129	    await this.payload.update({
130	      collection: 'users' as CollectionSlug,
131	      id: userId,
132	      data: {
133	        refreshToken,
134	        tokenExpiresAt: tokenExpiresAt.toISOString(),
135	        lastTokenUsedAt: new Date().toISOString(),
136	        lastLogin: new Date().toISOString(),
137	      } as any,
138	    })
139	
140	    return {
141	      accessToken,
142	      refreshToken,
143	      user: {
144	        id: userId,
145	        email,
146	        role,
147	      },
148	    }
149	  }
150	
151	  async refresh(refreshToken: string): Promise<{ accessToken: string; refreshToken: string }> {
152	    if (!refreshToken) {
153	      throw createError('Refresh token is required', 400)
154	    }
155	
156	    let payload: { userId: string; email: string; role: RbacRole; sessionId: string; generation: number }
157	    try {
158	      payload = await this.jwtService.verify(refreshToken) as any
159	    } catch {
160	      throw createError('Invalid or expired refresh token', 401)
161	    }
162	
163	    // Find user and verify stored refresh token matches
164	    const users = await this.payload.find({
165	      collection: 'users' as CollectionSlug,
166	      where: { id: { equals: payload.userId } },
167	      limit: 1,
168	    })
169	    const user = users.docs[0]
170	
171	    if (!user) {
172	      throw createError('User not found', 404)
173	    }
174	
175	    const storedRefreshToken = (user as any).refreshToken as string | null
176	    const tokenExpiresAt = (user as any).tokenExpiresAt as string | null
177	
178	    // Verify refresh token matches and is not expired
179	    if (storedRefreshToken !== refreshToken) {
180	      throw createError('Invalid refresh token', 401)
181	    }
182	
183	    if (tokenExpiresAt && new Date(tokenExpiresAt) < new Date()) {
184	      throw createError('Refresh token expired', 401)
185	    }
186	
187	    // Generate new tokens with incremented generation
188	    const newPayload = {
189	      ...payload,
190	      generation: payload.generation + 1,
191	    }
192	
193	    const newAccessToken = await this.jwtService.signAccessToken(newPayload)
194	    const newRefreshToken = await this.jwtService.signRefreshToken(newPayload)
195	
196	    // Update stored refresh token (rotation)
197	    const newTokenExpiresAt = new Date(Date.now() + REFRESH_TOKEN_EXPIRY_MS)
198	
199	    await this.payload.update({
200	      collection: 'users' as CollectionSlug,
201	      id: payload.userId,
202	      data: {
203	        refreshToken: newRefreshToken,
204	        tokenExpiresAt: newTokenExpiresAt.toISOString(),
205	        lastTokenUsedAt: new Date().toISOString(),
206	      } as any,
207	    })
208	
209	    return { accessToken: newAccessToken, refreshToken: newRefreshToken }
210	  }
211	
212	  async verifyAccessToken(accessToken: string): Promise<{ user?: AuthenticatedUser }> {
213	    if (!accessToken) {
214	      throw createError('Access token is required', 401)
215	    }
216	
217	    let payload: { userId: string; email: string; role: RbacRole; sessionId: string; generation: number }
218	    try {
219	      payload = await this.jwtService.verify(accessToken) as any
220	    } catch (err) {
221	      const message = err instanceof Error ? err.message : 'Invalid access token'
222	      throw createError(message, 401)
223	    }
224	
225	    const userResults = await this.payload.find({
226	      collection: 'users' as CollectionSlug,
227	      where: { id: { equals: payload.userId } },
228	      limit: 1,
229	    })
230	    const user = userResults.docs[0]
231	
232	    if (!user) {
233	      throw createError('User not found', 404)
234	    }
235	
236	    const isActive = (user as any).isActive ?? true
237	    if (!isActive) {
238	      throw createError('Account is inactive', 403)
239	    }
240	
241	    return {
242	      user: {
243	        id: (user as any).id,
244	        email: (user as any).email,
245	        role: (user as any).role as RbacRole,
246	        firstName: (user as any).firstName,
247	        lastName: (user as any).lastName,
248	        isActive,
249	      },
250	    }
251	  }
252	
253	  async logout(userId: number | string): Promise<void> {
254	    await this.payload.update({
255	      collection: 'users' as CollectionSlug,
256	      id: userId,
257	      data: {
258	        refreshToken: null,
259	      } as any,
260	    })
261	  }
262	}
