41	/**
42	 * Verifies a password against a Payload-stored hash using PBKDF2.
43	 * Matches Payload's generatePasswordSaltHash algorithm: 25000 iterations, sha256, 512 bits.
44	 */
45	async function verifyPassword(password: string, hash: string, salt: string): Promise<boolean> {
46	  return new Promise((resolve, reject) => {
47	    crypto.pbkdf2(password, salt, 25000, 512, 'sha256', (err, derivedKey) => {
48	      if (err) {
49	        reject(err)
50	        return
51	      }
52	      const storedHashBuffer = Buffer.from(hash, 'hex')
53	      if (derivedKey.length === storedHashBuffer.length && crypto.timingSafeEqual(derivedKey, storedHashBuffer)) {
54	        resolve(true)
55	      } else {
56	        resolve(false)
57	      }
58	    })
59	  })
60	}
